export type ColorPickerFormatProps = HTMLAttributes<HTMLDivElement>;

export const ColorPickerFormat = ({
  className,
  ...props
}: ColorPickerFormatProps) => {
  const { hue, saturation, lightness, alpha, mode } = useColorPicker();
  const color = Color.hsl(hue, saturation, lightness, alpha / 100);

  if (mode === "hex") {
    const hex = color.hex();

    return (
      <div
        className={cn(
          "-space-x-px relative flex w-full items-center rounded-md shadow-sm",
          className
        )}
        {...props}
      >
        <Input
          className="h-8 rounded-r-none bg-secondary px-2 text-xs shadow-none"
          readOnly
          type="text"
          value={hex}
        />
        <PercentageInput value={alpha} />
      </div>
    );
  }

  if (mode === "rgb") {
    const rgb = color
      .rgb()
      .array()
      .map((value) => Math.round(value));

    return (
      <div
        className={cn(
          "-space-x-px flex items-center rounded-md shadow-sm",
          className
        )}
        {...props}
      >
        {rgb.map((value, index) => (
          <Input
            className={cn(
              "h-8 rounded-r-none bg-secondary px-2 text-xs shadow-none",
              index && "rounded-l-none",
              className
            )}
            key={index}
            readOnly
            type="text"
            value={value}
          />
        ))}
        <PercentageInput value={alpha} />
      </div>
    );
  }

  if (mode === "css") {
    const rgb = color
      .rgb()
      .array()
      .map((value) => Math.round(value));

    return (
      <div className={cn("w-full rounded-md shadow-sm", className)} {...props}>
        <Input
          className="h-8 w-full bg-secondary px-2 text-xs shadow-none"
          readOnly
          type="text"
          value={`rgba(${rgb.join(", ")}, ${alpha}%)`}
          {...props}
        />
      </div>
    );
  }

  if (mode === "hsl") {
    const hsl = color
      .hsl()
      .array()
      .map((value) => Math.round(value));

    return (
      <div
        className={cn(
          "-space-x-px flex items-center rounded-md shadow-sm",
          className
        )}
        {...props}
      >
        {hsl.map((value, index) => (
          <Input
            className={cn(
              "h-8 rounded-r-none bg-secondary px-2 text-xs shadow-none",
              index && "rounded-l-none",
              className
            )}
            key={index}
            readOnly
            type="text"
            value={value}
          />
        ))}
        <PercentageInput value={alpha} />
      </div>
    );
  }

  return null;
};

/**
 * Numeric helpers shared across editor panels and drag controllers. Pure
 * functions only — anything tied to timeline semantics (snapping, timecode)
 * lives in its own module.
 */

/** Clamps `value` to `[min, max]`; either bound may be omitted. */
export function clamp(value: number, min?: number, max?: number): number {
  let next = value;
  if (min !== undefined) next = Math.max(min, next);
  if (max !== undefined) next = Math.min(max, next);
  return next;
}

/** Clamps `value` to the unit interval `[0, 1]`. */
export function clamp01(value: number): number {
  return clamp(value, 0, 1);
}

"use client";

// Effects: the effect stack (drag to reorder), blend mode, and the keyframable blur.

import { useState } from "react";
import {
  closestCenter,
  DndContext,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import { SortableContext, useSortable, verticalListSortingStrategy } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { GripVerticalIcon, PlusIcon, Trash2Icon, XIcon } from "@/lib/hugeicons";
import { useEditor, usePlayback } from "@mcut/react";
import {
  getEffectType,
  listEffectTypes,
  getAnimatedValue,
  hasKeyframes,
  type Effect,
  type TimelineElement,
} from "@mcut/timeline";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { KeyframeRowControls, localPlayheadMs } from "./keyframe-controls";
import { FieldRow, NumberField, Section } from "./inspector-fields";
import { PresetMenu } from "./preset-menu";

const BLEND_MODES = [
  "normal",
  "multiply",
  "screen",
  "overlay",
  "darken",
  "lighten",
  "color-dodge",
  "color-burn",
  "hard-light",
  "soft-light",
  "difference",
  "exclusion",
] as const;

function EffectRow({
  elementId,
  effect,
  index,
}: {
  elementId: string;
  effect: Effect;
  index: number;
}) {
  const engine = useEditor();
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: String(index),
  });
  const dispatch = (command: Record<string, unknown> & { type: string }) => {
    try {
      engine.dispatch(command);
    } catch (error) {
      // "Nothing happened" reads as a bug — say why the edit was refused.
      toast.error(error instanceof Error ? error.message : "Edit failed");
    }
  };
  // The effect type declares its own primary scrubbable param.
  const param = getEffectType(effect.type)?.param;
  const value = param ? ((effect as unknown as Record<string, number>)[param.key] ?? 0) : 0;
  return (
    <div
      ref={setNodeRef}
      style={{ transform: CSS.Transform.toString(transform), transition }}
      className={cn("flex items-center gap-1.5", isDragging && "relative z-10 opacity-80")}
    >
      <button
        type="button"
        title="Drag to reorder — the stack applies top to bottom"
        className="shrink-0 cursor-grab touch-none text-muted-foreground/60 hover:text-foreground active:cursor-grabbing"
        {...attributes}
        {...listeners}
      >
        <GripVerticalIcon className="size-3" />
      </button>
      <button
        type="button"
        title={effect.enabled ? "Click to disable" : "Click to enable"}
        className={cn(
          "w-14 shrink-0 truncate text-left text-xs capitalize",
          effect.enabled ? "text-foreground" : "text-muted-foreground line-through",
        )}
        onClick={() =>
          dispatch({ type: "updateEffect", elementId, index, patch: { enabled: !effect.enabled } })
        }
      >
        {effect.type.replace("-", " ")}
      </button>
      {param ? (
        <NumberField
          className="flex-1"
          value={Math.round(value * 100) / 100}
          min={param.min}
          max={param.max}
          step={(param.max - param.min) / 100}
          scrubPerPx={(param.max - param.min) / 200}
          {...(param.unit ? { unit: param.unit } : {})}
          onCommit={(next) =>
            dispatch({ type: "updateEffect", elementId, index, patch: { [param.key]: next } })
          }
        />
      ) : (
        <span className="flex-1 truncate font-mono text-2xs text-muted-foreground">
          {effect.type === "css" ? effect.filter : ""}
        </span>
      )}
      <Button
        variant="ghost"
        size="icon-xs"
        title="Remove effect"
        onClick={() => dispatch({ type: "removeEffect", elementId, index })}
      >
        <Trash2Icon />
      </Button>
    </div>
  );
}

export function EffectsSection({ element }: { element: TimelineElement }) {
  const engine = useEditor();
  const [adding, setAdding] = useState(false);
  const effects = ("effects" in element ? element.effects : undefined) ?? [];
  const blendMode = ("blendMode" in element ? element.blendMode : undefined) ?? "normal";
  // The `blur` fixed-effect property: keyframable blur on top of the static
  // stack (blur-in/out reveals). Committing a value keys it at the playhead.
  const blurArmed = hasKeyframes(element, "blur");
  const playheadMs = usePlayback((s) => (blurArmed ? Math.round(s.currentTimeMs) : -1));
  const nowMs = playheadMs >= 0 ? playheadMs : Math.round(engine.playback.state.currentTimeMs);
  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 4 } }));
  // Whole-stack preset: the effects list plus blend mode, applied through
  // updateElement so the merged element re-validates (bad data just toasts).
  const applyEffectsPreset = (values: Record<string, unknown>) => {
    const patch: Record<string, unknown> = {};
    if (Array.isArray(values.effects)) patch.effects = values.effects;
    if ("blendMode" in values) patch.blendMode = values.blendMode ?? undefined;
    engine.dispatch({ type: "updateElement", elementId: element.id, patch });
  };
  // Stack order is z-order for filters: drag rows to re-apply in a new order.
  const onDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over || active.id === over.id) return;
    try {
      engine.dispatch({
        type: "reorderEffect",
        elementId: element.id,
        fromIndex: Number(active.id),
        toIndex: Number(over.id),
      });
    } catch {
      // Element vanished mid-drag.
    }
  };
  return (
    <Section
      title="Effects"
      defaultOpen={effects.length > 0}
      actions={
        <>
          <Button
            variant="ghost"
            size="icon-xs"
            className="size-5 text-muted-foreground"
            title="Add effect"
            onClick={() => setAdding(true)}
          >
            <PlusIcon />
          </Button>
          <PresetMenu
            kind="effects"
            getValues={() => ({
              effects,
              blendMode: blendMode === "normal" ? null : blendMode,
            })}
            onApply={applyEffectsPreset}
          />
        </>
      }
    >
      <DndContext
        id={`mcut-effects-${element.id}`}
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={onDragEnd}
      >
        <SortableContext
          items={effects.map((_, index) => String(index))}
          strategy={verticalListSortingStrategy}
        >
          {effects.map((effect, index) => (
            <EffectRow
              key={`${effect.type}-${index}`}
              elementId={element.id}
              effect={effect}
              index={index}
            />
          ))}
        </SortableContext>
      </DndContext>
      {adding && (
        <FieldRow label="New">
          <Select
            value={null}
            onValueChange={(type) => {
              setAdding(false);
              if (!type) return;
              try {
                engine.dispatch({ type: "addEffect", elementId: element.id, effect: { type } });
              } catch {
                // Element vanished mid-edit.
              }
            }}
          >
            <SelectTrigger size="sm" className="w-full flex-1 text-xs">
              <SelectValue placeholder="Choose an effect…" />
            </SelectTrigger>
            <SelectContent>
              {listEffectTypes()
                .map((e) => e.type)
                .filter((type) => type !== "css")
                .map((type) => (
                  <SelectItem key={type} value={type} className="text-xs capitalize">
                    {type.replace("-", " ")}
                  </SelectItem>
                ))}
            </SelectContent>
          </Select>
          <Button variant="ghost" size="icon-xs" title="Cancel" onClick={() => setAdding(false)}>
            <XIcon />
          </Button>
        </FieldRow>
      )}
      <NumberField
        label="Blur"
        value={Math.round((blurArmed ? getAnimatedValue(element, "blur", nowMs) : 0) * 10) / 10}
        min={0}
        max={200}
        unit="px"
        scrubPerPx={0.5}
        onCommit={(radius) => {
          try {
            engine.dispatch({
              type: "setKeyframe",
              elementId: element.id,
              property: "blur",
              timeMs: localPlayheadMs(element, nowMs),
              value: radius,
            });
          } catch {
            // Element vanished mid-edit.
          }
        }}
        controls={<KeyframeRowControls element={element} property="blur" />}
      />
      <FieldRow label="Blend">
        <Select
          value={blendMode}
          onValueChange={(mode) =>
            engine.dispatch({
              type: "setBlendMode",
              elementId: element.id,
              blendMode: !mode || mode === "normal" ? null : mode,
            })
          }
        >
          <SelectTrigger size="sm" className="w-full flex-1 text-xs">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {BLEND_MODES.map((mode) => (
              <SelectItem key={mode} value={mode} className="text-xs capitalize">
                {mode.replace("-", " ")}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </FieldRow>
    </Section>
  );
}

"use client";

// Transition: the transition into the next flush clip.

import { useEditor } from "@mcut/react";
import { listTransitionTypes, type TimelineElement, type Track } from "@mcut/timeline";
import { Trash2Icon } from "@/lib/hugeicons";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { NumberField, Section } from "./inspector-fields";

export function TransitionSection({ element, track }: { element: TimelineElement; track: Track }) {
  const engine = useEditor();
  const transition = "transition" in element ? element.transition : undefined;
  const cutMs = element.startMs + element.durationMs;
  const nextClip = track.elements.find((e) => e.startMs === cutMs && e.id !== element.id);
  const dispatch = (value: { type: string; durationMs: number } | null) => {
    try {
      engine.dispatch({ type: "setTransition", elementId: element.id, transition: value });
    } catch {
      // No adjacent clip (or element vanished): inputs resync from state.
    }
  };
  return (
    <Section title="Transition" defaultOpen={transition !== undefined}>
      {transition ? (
        <>
          <div className="flex items-center gap-2">
            <span className="w-16 shrink-0 text-xs text-muted-foreground">Type</span>
            <Select
              value={transition.type}
              onValueChange={(type) =>
                type && dispatch({ type, durationMs: transition.durationMs })
              }
            >
              <SelectTrigger size="sm" className="w-full flex-1 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {listTransitionTypes().map((type) => (
                  <SelectItem key={type} value={type} className="text-xs capitalize">
                    {type.replace("-", " ")}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button
              variant="ghost"
              size="icon-xs"
              title="Remove transition"
              onClick={() => dispatch(null)}
            >
              <Trash2Icon />
            </Button>
          </div>
          <NumberField
            label="Length"
            value={transition.durationMs / 1000}
            step={0.1}
            min={0.1}
            max={5}
            unit="s"
            onCommit={(s) => dispatch({ type: transition.type, durationMs: Math.round(s * 1000) })}
          />
          {!nextClip && (
            <p className="text-2xs text-muted-foreground">
              Inactive — the next clip is no longer flush against this one.
            </p>
          )}
        </>
      ) : nextClip ? (
        <div className="flex items-center gap-2">
          <span className="w-16 shrink-0 text-xs text-muted-foreground">Into next</span>
          <Select
            value={null}
            onValueChange={(type) => type && dispatch({ type, durationMs: 500 })}
          >
            <SelectTrigger size="sm" className="w-full flex-1 text-xs">
              <SelectValue placeholder="Add a transition…" />
            </SelectTrigger>
            <SelectContent>
              {listTransitionTypes().map((type) => (
                <SelectItem key={type} value={type} className="text-xs capitalize">
                  {type.replace("-", " ")}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      ) : (
        <p className="text-2xs text-muted-foreground">
          Place another clip immediately after this one to add a transition.
        </p>
      )}
    </Section>
  );
}

"use client";

// Multicam: source roles, audio pick, sync nudges, waveform autosync, and the angle cut style.

import { useState } from "react";
import { useEditor } from "@mcut/react";
import { listTransitionTypes, type TimelineElement } from "@mcut/timeline";
import { findSyncOffsetMs } from "@mcut/media";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Spinner } from "./editor-primitives";
import { NumberField, Section } from "./inspector-fields";

export function MulticamSection({ element }: { element: TimelineElement & { type: "multicam" } }) {
  const engine = useEditor();
  const [syncing, setSyncing] = useState(false);
  const dispatch = (command: Record<string, unknown> & { type: string }) => {
    try {
      engine.dispatch(command);
    } catch (error) {
      // "Nothing happened" reads as a bug — say why the edit was refused.
      toast.error(error instanceof Error ? error.message : "Edit failed");
    }
  };

  /**
   * Waveform autosync: correlate every source's loudness envelope against
   * the first source and rewrite trims so the room audio lines up. The sync
   * nudge fields stay for the last word.
   */
  const autoSync = async () => {
    if (element.sources.length < 2 || syncing) return;
    setSyncing(true);
    try {
      const assets = engine.project.assets;
      const reference = element.sources[0]!;
      const referenceAsset = assets[reference.assetId];
      if (!referenceAsset) throw new Error("Reference media is missing");
      const trims = new Map<string, number>([[reference.key, reference.trimStartMs]]);
      let lowConfidence = false;
      for (const source of element.sources.slice(1)) {
        const asset = assets[source.assetId];
        if (!asset) continue;
        const result = await findSyncOffsetMs(referenceAsset.src, asset.src);
        if (!result) throw new Error(`"${source.key}" has no audio track to sync with`);
        if (result.confidence < 1.3) lowConfidence = true;
        // offsetMs = how much this source started AFTER the reference; its
        // trim compensates in the opposite direction.
        trims.set(source.key, reference.trimStartMs - result.offsetMs);
      }
      // Negative trims mean a source has no content yet at multicam start:
      // shift every trim up equally (relative sync is what matters).
      const lift = Math.max(0, -Math.min(...trims.values()));
      engine.transact(() => {
        for (const [sourceKey, trimStartMs] of trims) {
          dispatch({
            type: "setMulticamSourceTrim",
            elementId: element.id,
            sourceKey,
            trimStartMs: Math.round(trimStartMs + lift),
          });
        }
      });
      toast[lowConfidence ? "warning" : "success"](
        lowConfidence
          ? "Synced, but the waveforms barely matched — check it and nudge manually if needed"
          : "Sources synced by waveform",
      );
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Auto-sync failed");
    } finally {
      setSyncing(false);
    }
  };

  // Roles a source can take: every key the project's layout slots reference,
  // plus whatever the sources currently hold.
  const roleOptions = Array.from(
    new Set([
      ...engine.project.layouts.flatMap((layout) => layout.slots.map((slot) => slot.source)),
      ...element.sources.map((source) => source.key),
    ]),
  );

  return (
    <Section title="Multicam">
      {element.sources.map((source, i) => {
        const asset = engine.project.assets[source.assetId];
        const label = asset?.name ?? `Clip ${i + 1}`;
        return (
          <div key={source.key} className="flex items-center gap-2">
            <span className="w-16 shrink-0 truncate text-xs text-muted-foreground" title={label}>
              {label}
            </span>
            <Select
              value={source.key}
              onValueChange={(key) =>
                key &&
                key !== source.key &&
                dispatch({
                  type: "setMulticamSourceKey",
                  elementId: element.id,
                  sourceKey: source.key,
                  newKey: key,
                })
              }
            >
              <SelectTrigger size="sm" className="w-full flex-1 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {roleOptions.map((role) => (
                  <SelectItem key={role} value={role} className="text-xs capitalize">
                    {role}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        );
      })}
      <p className="text-2xs text-muted-foreground">
        Roles decide which layout slot shows each clip — picking a taken role swaps the two.
      </p>
      <div className="flex items-center gap-2">
        <span className="w-16 shrink-0 text-xs text-muted-foreground">Audio</span>
        <Select
          value={element.audioSource ?? "none"}
          onValueChange={(key) =>
            dispatch({
              type: "setMulticamAudio",
              elementId: element.id,
              sourceKey: !key || key === "none" ? null : key,
            })
          }
        >
          <SelectTrigger size="sm" className="w-full flex-1 text-xs">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="none" className="text-xs">
              Muted
            </SelectItem>
            {element.sources.map((source) => (
              <SelectItem key={source.key} value={source.key} className="text-xs capitalize">
                {source.key}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
      {element.sources.map((source) => (
        <NumberField
          key={source.key}
          label={`${source.key} sync`}
          value={source.trimStartMs / 1000}
          step={0.05}
          min={0}
          unit="s"
          onCommit={(seconds) =>
            dispatch({
              type: "setMulticamSourceTrim",
              elementId: element.id,
              sourceKey: source.key,
              trimStartMs: Math.round(seconds * 1000),
            })
          }
        />
      ))}
      {element.sources.length >= 2 && (
        <Button variant="outline" size="xs" disabled={syncing} onClick={() => void autoSync()}>
          {syncing && <Spinner />}
          {syncing ? "Listening…" : "Auto-sync by audio"}
        </Button>
      )}
      <div className="flex items-center gap-2">
        <span className="w-16 shrink-0 text-xs text-muted-foreground">Cut style</span>
        <Select
          value={element.angleTransition?.type ?? "cut"}
          onValueChange={(type) =>
            dispatch({
              type: "setMulticamAngleTransition",
              elementId: element.id,
              transition:
                !type || type === "cut"
                  ? null
                  : { type, durationMs: element.angleTransition?.durationMs ?? 500 },
            })
          }
        >
          <SelectTrigger size="sm" className="w-full flex-1 text-xs">
            <SelectValue className="capitalize">
              {element.angleTransition ? element.angleTransition.type.replace("-", " ") : "Jump cut"}
            </SelectValue>
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="cut" className="text-xs">
              Jump cut
            </SelectItem>
            {listTransitionTypes().map((type) => (
              <SelectItem key={type} value={type} className="text-xs capitalize">
                {type.replace("-", " ")}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
      {element.angleTransition && (
        <NumberField
          label="Blend"
          value={element.angleTransition.durationMs / 1000}
          step={0.1}
          min={0.1}
          max={5}
          unit="s"
          onCommit={(seconds) =>
            dispatch({
              type: "setMulticamAngleTransition",
              elementId: element.id,
              transition: {
                type: element.angleTransition!.type,
                durationMs: Math.round(seconds * 1000),
              },
            })
          }
        />
      )}
      <p className="text-2xs text-muted-foreground">
        {element.angles.length} cut{element.angles.length === 1 ? "" : "s"} — switch with 1–9 in
        Multicam mode (cuts while playing, corrects while paused). The cut style applies to every
        switch.
      </p>
      <Button
        variant="outline"
        size="xs"
        onClick={() => dispatch({ type: "flattenMulticam", elementId: element.id })}
      >
        Flatten to plain clips
      </Button>
    </Section>
  );
}

"use client";

// The full typography stack for text elements, plus the canvas text-measurement helpers.

import { layoutTextBlock, measureWith, type SizeHelpers } from "@mcut/compositor";
import {
  type Project,
  type TextBox,
  type TextRun,
  type TextStyle,
} from "@mcut/timeline";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { FontPicker } from "./font-picker";
import { closestWeight, ensureFontLoaded, findFontOption } from "./font-library";
import { ChoiceRow, ColorField, FieldRow, NumberField } from "./inspector-fields";
import { ShadowFields, StrokeFields } from "./style-fields";

const WEIGHT_LABELS: Record<number, string> = {
  100: "Thin",
  200: "ExtraLight",
  300: "Light",
  400: "Regular",
  500: "Medium",
  600: "SemiBold",
  700: "Bold",
  800: "ExtraBold",
  900: "Black",
};

/**
 * The full typography stack for text elements: family (font library picker),
 * weight/italic from the family's real faces, size, tracking, line height,
 * case, alignment, colors, outline, and drop shadow — the CapCut/Canva
 * table-stakes set for thumbnail text.
 */
export function TextStyleSection({
  style,
  patchStyle,
  spacing,
}: {
  style: TextStyle;
  patchStyle: (values: Record<string, unknown>) => void;
  /** Keyframe-aware Spacing row wiring (text elements; captions omit it). */
  spacing?: { value: number; onCommit: (value: number) => void; controls: React.ReactNode };
}) {
  const option = findFontOption(style.fontFamily);
  const weights = option?.weights ?? [100, 200, 300, 400, 500, 600, 700, 800, 900];
  const weightItems = weights.includes(style.fontWeight)
    ? weights
    : [...weights, style.fontWeight].sort((a, b) => a - b);
  const italic = style.fontStyle === "italic";
  // Variable families expose the whole wght axis; static ones their cuts.
  const axis = option?.variableWeight;

  const setFamily = (fontFamily: string) => {
    // Keep the weight where the new family can express it: clamp onto a
    // variable axis, else snap to the nearest static face.
    const next = findFontOption(fontFamily);
    const fontWeight = next?.variableWeight
      ? Math.round(
          Math.min(next.variableWeight.max, Math.max(next.variableWeight.min, style.fontWeight)),
        )
      : next
        ? closestWeight(next.weights, style.fontWeight)
        : style.fontWeight;
    const fontStyle = italic && next && !next.hasItalic ? "normal" : style.fontStyle;
    patchStyle({ fontFamily, fontWeight, fontStyle });
  };

  const setWeight = (fontWeight: number) => {
    void ensureFontLoaded(style.fontFamily, fontWeight, italic);
    patchStyle({ fontWeight });
  };

  const italicButton = (
    <Button
      variant={italic ? "secondary" : "ghost"}
      size="icon-xs"
      title="Italic"
      onClick={() => {
        const fontStyle = italic ? "normal" : "italic";
        void ensureFontLoaded(style.fontFamily, style.fontWeight, fontStyle === "italic");
        patchStyle({ fontStyle });
      }}
    >
      <span className="font-serif text-xs italic">I</span>
    </Button>
  );

  return (
    <>
      <div className="flex items-center gap-2">
        <span className="w-16 shrink-0 text-xs text-muted-foreground">Font</span>
        <FontPicker
          value={style.fontFamily}
          weight={style.fontWeight}
          italic={italic}
          onSelect={setFamily}
          className="flex-1"
        />
      </div>
      {axis ? (
        // Variable font: the full weight axis, scrubbable like any number.
        <NumberField
          label="Weight"
          value={style.fontWeight}
          min={axis.min}
          max={axis.max}
          step={10}
          scrubPerPx={4}
          onCommit={(w) => setWeight(Math.round(w))}
          controls={italicButton}
        />
      ) : (
        <FieldRow label="Weight">
          <Select
            value={String(style.fontWeight)}
            onValueChange={(w) => w && setWeight(Number(w))}
          >
            <SelectTrigger size="sm" className="w-full flex-1 text-xs">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {weightItems.map((w) => (
                <SelectItem key={w} value={String(w)} className="text-xs">
                  {WEIGHT_LABELS[w] ?? String(w)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {italicButton}
        </FieldRow>
      )}
      <NumberField
        label="Size"
        value={style.fontSize}
        min={4}
        unit="px"
        onCommit={(fontSize) => patchStyle({ fontSize })}
      />
      <NumberField
        label="Spacing"
        value={spacing?.value ?? style.letterSpacing}
        step={0.5}
        min={-50}
        max={200}
        unit="px"
        scrubPerPx={0.25}
        onCommit={spacing?.onCommit ?? ((letterSpacing) => patchStyle({ letterSpacing }))}
        controls={spacing?.controls}
      />
      <NumberField
        label="Line"
        value={style.lineHeight}
        step={0.05}
        min={0.5}
        max={3}
        unit="x"
        scrubPerPx={0.01}
        onCommit={(lineHeight) => patchStyle({ lineHeight })}
      />
      <div className="flex items-center gap-2">
        <span className="w-16 shrink-0 text-xs text-muted-foreground">Case</span>
        <div className="flex flex-1 gap-1">
          {(
            [
              ["none", "—", "As typed"],
              ["uppercase", "AG", "UPPERCASE"],
              ["lowercase", "ag", "lowercase"],
            ] as const
          ).map(([transform, label, title]) => (
            <Button
              key={transform}
              size="xs"
              variant={style.textTransform === transform ? "secondary" : "ghost"}
              className="flex-1"
              title={title}
              onClick={() => patchStyle({ textTransform: transform })}
            >
              {label}
            </Button>
          ))}
        </div>
      </div>
      <ChoiceRow
        label="Align"
        value={style.align}
        options={["left", "center", "right"] as const}
        onCommit={(align) => patchStyle({ align })}
      />
      <ColorField
        label="Color"
        value={style.color}
        onCommit={(color) => patchStyle({ color })}
      />
      <ColorField
        label="Fill"
        value={style.backgroundColor ?? "rgba(0, 0, 0, 0)"}
        onCommit={(backgroundColor) => patchStyle({ backgroundColor })}
      />
      {/* Outline + shadow are the shared style primitives — the same rows
          (and presets) media frames and layout slots use. */}
      <StrokeFields
        label="Outline"
        defaultColor="#000000"
        value={style.stroke}
        onCommit={(stroke) => patchStyle({ stroke })}
      />
      <ShadowFields value={style.shadow} onCommit={(shadow) => patchStyle({ shadow })} />
    </>
  );
}

let measureCanvas: HTMLCanvasElement | null = null;

function getMeasureContext(): CanvasRenderingContext2D | null {
  if (typeof document === "undefined") return null;
  measureCanvas ??= document.createElement("canvas");
  return measureCanvas.getContext("2d");
}

function measureTextElement(text: string, style: TextStyle, box?: TextBox, runs?: readonly TextRun[]) {
  const ctx = getMeasureContext();
  if (!ctx) return null;
  const layout = layoutTextBlock(measureWith(ctx), text, style, {
    box,
    ...(runs ? { runs } : {}),
  });
  return { width: layout.width, height: layout.height };
}

export function sizeHelpersForProject(project: Project): SizeHelpers {
  return {
    getAssetSize: (assetId) => {
      const asset = project.assets[assetId];
      return asset?.width && asset?.height ? { width: asset.width, height: asset.height } : null;
    },
    measureText: (text, style, box, runs) => measureTextElement(text, style, box, runs) ?? { width: 0, height: 0 },
  };
}

"use client";

// Inspector for the layout slot being edited on the canvas (multicam mode).

import { useEditor, useProject } from "@mcut/react";
import {
  createLayoutId,
  type Layout,
  type LayoutSlot,
} from "@mcut/timeline";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { useEditorUI } from "./editor-ui";
import { roundRect, safeAreaRect, saveLayoutSlot } from "./layout-slot-editor";
import { ChoiceRow, FieldRow, NumberField, Section } from "./inspector-fields";
import { FrameFields, type FrameTarget } from "./frame-section";
import { PresetMenu } from "./preset-menu";
import { RadiusRow, readStylePreset, StrokeFields } from "./style-fields";

/** Aspect chips for quick crops: keep the slot's center and pixel width. */
export const SLOT_ASPECTS: ReadonlyArray<readonly [label: string, ratio: number]> = [
  ["1:1", 1],
  ["3:4", 3 / 4],
  ["4:3", 4 / 3],
  ["16:9", 16 / 9],
  ["9:16", 9 / 16],
];

/**
 * Inspector for the layout slot being edited on the canvas (multicam mode).
 * The canvas does direct manipulation (move / resize / crop-pan); everything
 * with a value lives here, in the same controls as element properties.
 */
export function LayoutSlotInspector({ layout, className }: { layout: Layout; className?: string }) {
  const engine = useEditor();
  const project = useProject();
  const { editingSlotIndex, setEditingSlotIndex } = useEditorUI();
  const W = project.width;
  const H = project.height;
  const index =
    editingSlotIndex !== null && layout.slots[editingSlotIndex] !== undefined
      ? editingSlotIndex
      : null;
  const slot = index !== null ? layout.slots[index]! : null;
  const safe = safeAreaRect(W, H);

  const save = (patch: Partial<LayoutSlot>, options?: { history?: boolean }) => {
    if (index !== null) saveLayoutSlot(engine, layout, index, patch, options);
  };
  const saveRect = (rect: LayoutSlot["rect"], options?: { history?: boolean }) =>
    save({ rect: roundRect(rect) }, options);

  const applyAspect = (ratio: number) => {
    if (!slot) return;
    // Hold the center and the pixel width; derive the height (shrink to fit).
    let w = slot.rect.w;
    let h = (slot.rect.w * W) / ratio / H;
    if (h > 1) {
      w /= h;
      h = 1;
    }
    const cx = slot.rect.x + slot.rect.w / 2;
    const cy = slot.rect.y + slot.rect.h / 2;
    saveRect({ x: cx - w / 2, y: cy - h / 2, w, h });
  };

  // The shared frame editor drives the slot through px-rect reads/writes;
  // normalized storage stays an adapter detail.
  const slotFrame: FrameTarget | null =
    slot === null
      ? null
      : {
          canvas: { width: W, height: H },
          safe: { x: safe.x * W, y: safe.y * H, width: safe.w * W, height: safe.h * H },
          rect: {
            x: slot.rect.x * W,
            y: slot.rect.y * H,
            width: slot.rect.w * W,
            height: slot.rect.h * H,
          },
          minSize: 16,
          setRect: (patch) => {
            const next = { ...slot.rect };
            if (patch.x !== undefined) next.x = patch.x / W;
            if (patch.y !== undefined) next.y = patch.y / H;
            if (patch.width !== undefined) next.w = patch.width / W;
            if (patch.height !== undefined) next.h = patch.height / H;
            saveRect(next);
          },
        };

  const saveAsPreset = () => {
    const name = window.prompt("Save this layout as a new preset:", `${layout.name} copy`);
    if (!name?.trim()) return;
    try {
      engine.dispatch({
        type: "saveLayout",
        layout: { ...layout, id: createLayoutId(), name: name.trim() },
      });
      toast.success(`"${name.trim()}" added to the layout bank`);
    } catch {
      toast.error("Could not save the preset");
    }
  };

  return (
    <div className={cn("flex flex-col gap-1 p-3", className)}>
      <div className="flex items-center gap-2 pb-1">
        <span className="flex-1 truncate text-xs font-semibold" title={layout.name}>
          Layout · {layout.name}
        </span>
        <Button variant="secondary" size="xs" onClick={saveAsPreset}>
          Save as preset
        </Button>
      </div>

      <Section title="Slots">
        {layout.slots.map((s, i) => (
          <button
            key={`${s.source}-${i}`}
            type="button"
            className={cn(
              "flex items-center justify-between rounded-md border px-2 py-1 text-xs capitalize",
              i === index
                ? "border-primary bg-primary/10 text-foreground"
                : "border-transparent text-muted-foreground hover:bg-foreground/5 hover:text-foreground",
            )}
            onClick={() => setEditingSlotIndex(i)}
          >
            {s.source}
            <span className="text-2xs text-muted-foreground normal-case">
              {layout.slots.length > 1 && i === layout.slots.length - 1
                ? "top"
                : layout.slots.length > 1 && i === 0
                  ? "bottom"
                  : ""}
            </span>
          </button>
        ))}
        {slot === null && (
          <p className="text-2xs text-muted-foreground">
            Click a slot above or on the canvas to style it.
          </p>
        )}
      </Section>

      {slot && index !== null && slotFrame && (
        <>
          <Section title="Frame">
            <FrameFields target={slotFrame} />
            <FieldRow
              label="Aspect"
              title="Crop the slot to an aspect (keeps its center and width)"
            >
              <div className="grid min-w-0 flex-1 grid-cols-3 gap-1">
                {SLOT_ASPECTS.map(([label, ratio]) => (
                  <Button
                    key={label}
                    size="xs"
                    variant="outline"
                    className="min-w-0 px-1"
                    onClick={() => applyAspect(ratio)}
                  >
                    {label}
                  </Button>
                ))}
              </div>
            </FieldRow>
            <FieldRow label="Fill">
              <Button
                size="xs"
                variant="outline"
                className="flex-1"
                title="Fit the slot to the safe area"
                onClick={() => saveRect(safe)}
              >
                Safe area
              </Button>
              <Button
                size="xs"
                variant="outline"
                className="flex-1"
                title="Fill the whole canvas"
                onClick={() => saveRect({ x: 0, y: 0, w: 1, h: 1 })}
              >
                Screen
              </Button>
            </FieldRow>
          </Section>

          <Section
            title="Style"
            actions={
              <PresetMenu
                kind="style"
                getValues={() => ({
                  fit: slot.fit,
                  cornerRadius: slot.cornerRadius,
                  shadow: slot.shadow,
                  stroke: slot.stroke ?? null,
                })}
                onApply={(values) => {
                  // Tolerant apply: slots keep the keys they understand; a
                  // full element shadow lands as the slot's boolean look.
                  const preset = readStylePreset(values);
                  const patch: Partial<LayoutSlot> = {};
                  if (preset.fit) patch.fit = preset.fit;
                  if (preset.cornerRadius !== undefined) patch.cornerRadius = preset.cornerRadius;
                  if (preset.stroke !== undefined) patch.stroke = preset.stroke ?? undefined;
                  if (preset.shadow !== undefined) {
                    patch.shadow =
                      typeof preset.shadow === "boolean" ? preset.shadow : preset.shadow !== null;
                  }
                  save(patch);
                }}
              />
            }
          >
            <ChoiceRow
              label="Fit"
              value={slot.fit}
              options={["cover", "contain"] as const}
              onCommit={(fit) => save({ fit })}
            />
            <RadiusRow
              value={slot.cornerRadius}
              onCommit={(cornerRadius) => save({ cornerRadius })}
            />
            <StrokeFields
              value={slot.stroke}
              onCommit={(stroke) => save({ stroke })}
            />
            <FieldRow label="Shadow">
              <Switch
                aria-label="Shadow"
                checked={slot.shadow}
                onCheckedChange={(shadow) => save({ shadow })}
              />
            </FieldRow>
          </Section>

          {slot.fit === "cover" && (
            <Section title="Crop" onReset={() => save({ focus: { x: 0.5, y: 0.5 } })}>
              <NumberField
                label="Focus X"
                value={Math.round((slot.focus?.x ?? 0.5) * 100)}
                min={0}
                max={100}
                unit="%"
                scrubPerPx={0.5}
                onCommit={(pct) => save({ focus: { y: slot.focus?.y ?? 0.5, x: pct / 100 } })}
              />
              <NumberField
                label="Focus Y"
                value={Math.round((slot.focus?.y ?? 0.5) * 100)}
                min={0}
                max={100}
                unit="%"
                scrubPerPx={0.5}
                onCommit={(pct) => save({ focus: { x: slot.focus?.x ?? 0.5, y: pct / 100 } })}
              />
              <p className="text-2xs text-muted-foreground">
                Or double-click the slot on the canvas and drag to pan the source inside the
                frame.
              </p>
            </Section>
          )}

          <p className="text-2xs text-muted-foreground">
            On the canvas: drag to move (snaps to the safe area, center, and other slots — hold ⌘
            to disable), corners resize with the aspect locked (Shift frees it), arrows nudge by
            1px.
          </p>
        </>
      )}
    </div>
  );
}
